#!/usr/bin/env python3\n\"\"\"Reddington AI Assistant - Python Backend\n\nThis is the main entry point for the Reddington backend service.\nIt runs a FastAPI server that processes user input and coordinates\nwith the C# desktop application.\n\nUsage:\n    python main.py              # Run with defaults\n    python main.py --host 0.0.0.0 --port 8000  # Custom host/port\n    python main.py --reload    # Development mode with auto-reload\n\"\"\"\n\nimport logging\nimport sys\nfrom pathlib import Path\nfrom contextlib import asynccontextmanager\n\nfrom fastapi import FastAPI, WebSocket, HTTPException, Request\nfrom fastapi.middleware.cors import CORSMiddleware\nfrom fastapi.middleware.gzip import GZipMiddleware\nimport uvicorn\n\nfrom config import config\n\n# Configure logging\nlogging.basicConfig(\n    level=config.LOG_LEVEL,\n    format=config.LOG_FORMAT,\n    handlers=[\n        logging.FileHandler(config.LOG_FILE),\n        logging.StreamHandler(sys.stdout)\n    ]\n)\n\nlogger = logging.getLogger(__name__)\n\n# Global state for application lifecycle\nlifespan_state = {\n    'initialized': False,\n    'services': {},\n}\n\n\n@asynccontextmanager\nasync def lifespan(app: FastAPI):\n    \"\"\"Application lifespan context manager for startup/shutdown events\"\"\"\n    # Startup\n    logger.info(\"=\"*60)\n    logger.info(f\"Reddington Backend v{config.APP_VERSION} Starting...\")\n    logger.info(f\"Mode: {'Development' if config.DEBUG_MODE else 'Production'}\")\n    logger.info(f\"Listening on {config.PYTHON_HOST}:{config.PYTHON_PORT}\")\n    logger.info(\"=\"*60)\n    \n    try:\n        # Initialize services here\n        logger.info(\"Initializing core services...\")\n        lifespan_state['initialized'] = True\n        logger.info(\"✓ Backend initialization complete\")\n    except Exception as e:\n        logger.error(f\"✗ Backend initialization failed: {e}\", exc_info=True)\n        raise\n    \n    yield\n    \n    # Shutdown\n    logger.info(\"Reddington Backend shutting down...\")\n    lifespan_state['initialized'] = False\n    logger.info(\"✓ Backend shutdown complete\")\n\n\n# Create FastAPI application\napp = FastAPI(\n    title=\"Reddington AI Assistant Backend\",\n    description=\"Backend service for Reddington - Personal AI Operating System\",\n    version=config.APP_VERSION,\n    docs_url=\"/docs\" if config.DEBUG_MODE else None,  # Disable docs in production\n    redoc_url=\"/redoc\" if config.DEBUG_MODE else None,\n    lifespan=lifespan\n)\n\n# Add middleware\n\n# CORS Configuration\napp.add_middleware(\n    CORSMiddleware,\n    allow_origins=[\"http://localhost:*\", \"http://127.0.0.1:*\"],\n    allow_credentials=True,\n    allow_methods=[\"*\"],\n    allow_headers=[\"*\"],\n    max_age=3600,\n)\n\n# Gzip compression for responses\napp.add_middleware(GZipMiddleware, minimum_size=1000)\n\n\n# Health Check Endpoints\n\n@app.get(\"/health\", tags=[\"Health\"])\nasync def health_check():\n    \"\"\"Simple health check endpoint\"\"\"\n    return {\n        \"status\": \"healthy\",\n        \"initialized\": lifespan_state.get('initialized', False),\n        \"version\": config.APP_VERSION\n    }\n\n\n@app.get(\"/api/status\", tags=[\"Status\"])\nasync def get_status():\n    \"\"\"Get detailed backend status\"\"\"\n    return {\n        \"backend\": \"online\",\n        \"version\": config.APP_VERSION,\n        \"debug_mode\": config.DEBUG_MODE,\n        \"initialized\": lifespan_state.get('initialized', False),\n        \"timestamp\": None  # Will be set by response\n    }\n\n\n# Core Processing Endpoints\n\n@app.post(\"/api/process-input\", tags=[\"Processing\"])\nasync def process_user_input(request: dict):\n    \"\"\"Process user input from C# desktop application\n    \n    Request format:\n    {\n        \"type\": \"text\"|\"voice\",\n        \"content\": \"user input\",\n        \"context\": {}\n    }\n    \"\"\"\n    try:\n        user_input = request.get(\"content\")\n        input_type = request.get(\"type\", \"text\")\n        \n        if not user_input:\n            raise HTTPException(status_code=400, detail=\"Content is required\")\n        \n        logger.info(f\"Processing {input_type} input: {user_input[:100]}\")\n        \n        # TODO: Implement actual processing logic\n        # 1. Intent recognition\n        # 2. Service selection\n        # 3. Execute appropriate service\n        # 4. Format response\n        \n        return {\n            \"status\": \"success\",\n            \"response\": f\"Processing: {user_input}\",\n            \"action\": None,\n            \"timestamp\": None\n        }\n    except HTTPException:\n        raise\n    except Exception as e:\n        logger.error(f\"Error processing input: {e}\", exc_info=True)\n        raise HTTPException(status_code=500, detail=str(e))\n\n\n# System Endpoints\n\n@app.get(\"/api/permissions\", tags=[\"System\"])\nasync def check_permissions():\n    \"\"\"Check current system permissions status\"\"\"\n    return {\n        \"microphone\": True,\n        \"camera\": True,\n        \"filesystem\": True,\n        \"network\": True,\n        \"admin\": False\n    }\n\n\n@app.post(\"/api/initialize\", tags=[\"System\"])\nasync def initialize():\n    \"\"\"Initialize backend (called from C# on startup)\"\"\"\n    if lifespan_state.get('initialized'):\n        return {\"status\": \"already_initialized\"}\n    \n    try:\n        # Run initialization logic\n        lifespan_state['initialized'] = True\n        return {\"status\": \"initialized\", \"version\": config.APP_VERSION}\n    except Exception as e:\n        logger.error(f\"Initialization failed: {e}\", exc_info=True)\n        raise HTTPException(status_code=500, detail=str(e))\n\n\n# Audio Endpoints\n\n@app.post(\"/api/audio/transcribe\", tags=[\"Audio\"])\nasync def transcribe_audio(request: dict):\n    \"\"\"Transcribe audio to text (STT)\"\"\"\n    try:\n        # audio_data = request.get(\"audio_base64\")\n        # TODO: Implement STT\n        return {\n            \"status\": \"success\",\n            \"text\": \"Transcribed text will appear here\"\n        }\n    except Exception as e:\n        logger.error(f\"Transcription error: {e}\")\n        raise HTTPException(status_code=500, detail=str(e))\n\n\n@app.post(\"/api/audio/synthesize\", tags=[\"Audio\"])\nasync def synthesize_speech(request: dict):\n    \"\"\"Synthesize text to speech (TTS)\"\"\"\n    try:\n        text = request.get(\"text\")\n        if not text:\n            raise HTTPException(status_code=400, detail=\"Text is required\")\n        \n        # TODO: Implement TTS\n        return {\n            \"status\": \"success\",\n            \"audio_base64\": \"base64-encoded-audio-data\"\n        }\n    except HTTPException:\n        raise\n    except Exception as e:\n        logger.error(f\"Synthesis error: {e}\")\n        raise HTTPException(status_code=500, detail=str(e))\n\n\n# WebSocket Endpoints\n\n@app.websocket(\"/ws/audio-stream\")\nasync def websocket_audio_endpoint(websocket: WebSocket):\n    \"\"\"WebSocket endpoint for real-time audio streaming\"\"\"\n    await websocket.accept()\n    logger.info(\"Audio stream connection established\")\n    \n    try:\n        while True:\n            # Receive audio data from client\n            data = await websocket.receive_bytes()\n            \n            # Process audio chunk\n            logger.debug(f\"Received {len(data)} bytes of audio\")\n            \n            # Send processing status\n            await websocket.send_json({\n                \"status\": \"processing\",\n                \"bytes_received\": len(data)\n            })\n    except Exception as e:\n        logger.error(f\"WebSocket error: {e}\")\n    finally:\n        await websocket.close(code=1000)\n        logger.info(\"Audio stream connection closed\")\n\n\n# Error Handler\n\n@app.exception_handler(HTTPException)\nasync def http_exception_handler(request: Request, exc: HTTPException):\n    \"\"\"Handle HTTP exceptions\"\"\"\n    logger.warning(f\"HTTP {exc.status_code}: {exc.detail}\")\n    return {\n        \"status\": \"error\",\n        \"error_code\": exc.status_code,\n        \"message\": exc.detail\n    }\n\n\n@app.exception_handler(Exception)\nasync def general_exception_handler(request: Request, exc: Exception):\n    \"\"\"Handle general exceptions\"\"\"\n    logger.error(f\"Unhandled exception: {exc}\", exc_info=True)\n    return {\n        \"status\": \"error\",\n        \"error_code\": 500,\n        \"message\": \"Internal server error\"\n    }\n\n\n# Startup/Shutdown Events (alternative to lifespan)\n\n@app.on_event(\"startup\")\nasync def startup_event():\n    \"\"\"Called on application startup\"\"\"\n    logger.info(\"Startup event triggered\")\n\n\n@app.on_event(\"shutdown\")\nasync def shutdown_event():\n    \"\"\"Called on application shutdown\"\"\"\n    logger.info(\"Shutdown event triggered\")\n\n\nif __name__ == \"__main__\":\n    import argparse\n    \n    parser = argparse.ArgumentParser(description=\"Reddington Backend Server\")\n    parser.add_argument(\"--host\", default=config.PYTHON_HOST, help=\"Host to bind to\")\n    parser.add_argument(\"--port\", type=int, default=config.PYTHON_PORT, help=\"Port to bind to\")\n    parser.add_argument(\"--reload\", action=\"store_true\", help=\"Enable auto-reload\")\n    \n    args = parser.parse_args()\n    \n    logger.info(f\"Starting server: {args.host}:{args.port}\")\n    \n    uvicorn.run(\n        \"main:app\",\n        host=args.host,\n        port=args.port,\n        reload=args.reload or config.DEBUG_MODE,\n        log_level=config.LOG_LEVEL.lower(),\n        access_log=config.DEBUG_MODE\n    )\n